current_user = USERS["1"]

EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")

def require_admin(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        if not current_user or getattr(current_user, "role", None) != Role.ADMIN.value:
            return jsonify({"error": "forbidden", "message": "Administrator access required"}), 403
        return fn(*args, **kwargs)
    return wrapper

def find_user_by_id(user_id):
    return USERS.get(str(user_id))

def email_in_use(email, exclude_user_id=None):
    email_lower = email.lower()
    for uid, user in USERS.items():
        if uid != str(exclude_user_id) and user.email.lower() == email_lower:
            return True
    return False

def username_in_use(username, exclude_user_id=None):
    username_lower = username.lower()
    for uid, user in USERS.items():
        if uid != str(exclude_user_id) and user.username.lower() == username_lower:
            return True
    return False

def validate_payload(payload):
    allowed_fields = {
        "email",
        "username",
        "role",
        "account_status",
        "subscription_tier",
    }

    if not isinstance(payload, dict):
        return {"body": "Request body must be a JSON object"}

    unknown_fields = set(payload.keys()) - allowed_fields
    if unknown_fields:
        return {"fields": {field: "Unknown field" for field in sorted(unknown_fields)}}

    if not payload:
        return {"body": "At least one updatable field is required"}

    errors = {}

    if "email" in payload:
        email = payload["email"]
        if not isinstance(email, str) or not email.strip():
            errors["email"] = "Email must be a non-empty string"
        elif not EMAIL_RE.match(email.strip()):
            errors["email"] = "Invalid email format"

    if "username" in payload:
        username = payload["username"]
        if not isinstance(username, str) or not username.strip():
            errors["username"] = "Username must be a non-empty string"
        elif len(username.strip()) < 3 or len(username.strip()) > 50:
            errors["username"] = "Username must be between 3 and 50 characters"

    if "role" in payload:
        role = payload["role"]
        if role not in {r.value for r in Role}:
            errors["role"] = f"Role must be one of: {', '.join(r.value for r in Role)}"

    if "account_status" in payload:
        account_status = payload["account_status"]
        if account_status not in {s.value for s in AccountStatus}:
            errors["account_status"] = f"Account status must be one of: {', '.join(s.value for s in AccountStatus)}"

    if "subscription_tier" in payload:
        subscription_tier = payload["subscription_tier"]
        if subscription_tier not in {t.value for t in SubscriptionTier}:
            errors["subscription_tier"] = f"Subscription tier must be one of: {', '.join(t.value for t in SubscriptionTier)}"

    return errors

@app.put("/api/users/<user_id>")
@require_admin
def update_user(user_id):
    user = find_user_by_id(user_id)
    if not user:
        return jsonify({"error": "not_found", "message": "User not found"}), 404

    payload = request.get_json(silent=True)
    if payload is None:
        return jsonify({"error": "invalid_json", "message": "Request body must be valid JSON"}), 400

    validation_errors = validate_payload(payload)
    if validation_errors:
        return jsonify({"error": "validation_error", "details": validation_errors}), 400

    updates = {}

    if "email" in payload:
        email = payload["email"].strip().lower()
        if email_in_use(email, exclude_user_id=user.id):
            return jsonify({"error": "conflict", "message": "Email is already in use"}), 409
        updates["email"] = email

    if "username" in payload:
        username = payload["username"].strip()
        if username_in_use(username, exclude_user_id=user.id):
            return jsonify({"error": "conflict", "message": "Username is already in use"}), 409
        updates["username"] = username

    if "role" in payload:
        updates["role"] = payload["role"]

    if "account_status" in payload:
        updates["account_status"] = payload["account_status"]

    if "subscription_tier" in payload:
        updates["subscription_tier"] = payload["subscription_tier"]

    if user.id == current_user.id and updates.get("role") and updates["role"] != Role.ADMIN.value:
        return jsonify({"error": "forbidden", "message": "Administrators cannot demote themselves"}), 403

    for key, value in updates.items():
        setattr(user, key, value)

    return jsonify({
        "message": "User updated successfully",
        "user": user.to_dict()
    }), 200

